import{_ as e,o as a,c as t,ag as i}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"Security","description":"","frontmatter":{},"headers":[],"relativePath":"account/security.md","filePath":"account/security.md"}'),r={name:"account/security.md"};function n(s,o,l,c,u,d){return a(),t("div",null,[...o[0]||(o[0]=[i('<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><p>Protect your account with strong authentication and monitor access.</p><h2 id="password" tabindex="-1">Password <a class="header-anchor" href="#password" aria-label="Permalink to &quot;Password&quot;">​</a></h2><p>Use a strong, unique password for your MyCompanyDesk account. Change it from <strong>Profile &gt; Password</strong>.</p><h3 id="password-requirements" tabindex="-1">Password requirements <a class="header-anchor" href="#password-requirements" aria-label="Permalink to &quot;Password requirements&quot;">​</a></h3><ul><li>At least 8 characters</li><li>Mix of letters, numbers, and symbols recommended</li></ul><h2 id="two-factor-authentication" tabindex="-1">Two-factor authentication <a class="header-anchor" href="#two-factor-authentication" aria-label="Permalink to &quot;Two-factor authentication&quot;">​</a></h2><p>Add an extra layer of security to your account:</p><ol><li>Go to <strong>Profile &gt; Security</strong></li><li>Click <strong>Enable Two-Factor Authentication</strong></li><li>Scan the QR code with your authenticator app (Google Authenticator, Authy, etc.)</li><li>Enter the verification code to confirm</li><li>Save your <strong>recovery codes</strong> in a secure location</li></ol><p>With 2FA enabled, you&#39;ll need both your password and a code from your authenticator app to log in.</p><h3 id="disabling-2fa" tabindex="-1">Disabling 2FA <a class="header-anchor" href="#disabling-2fa" aria-label="Permalink to &quot;Disabling 2FA&quot;">​</a></h3><ol><li>Go to <strong>Profile &gt; Security</strong></li><li>Click <strong>Disable Two-Factor Authentication</strong></li><li>Enter your password to confirm</li></ol><h2 id="session-management" tabindex="-1">Session management <a class="header-anchor" href="#session-management" aria-label="Permalink to &quot;Session management&quot;">​</a></h2><p>View and manage your active sessions:</p><ul><li>See all devices and browsers where you&#39;re logged in</li><li>View last activity time for each session</li><li><strong>Revoke</strong> sessions you don&#39;t recognize</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>If you see a session you don&#39;t recognize, revoke it immediately and change your password.</p></div><h2 id="social-login" tabindex="-1">Social login <a class="header-anchor" href="#social-login" aria-label="Permalink to &quot;Social login&quot;">​</a></h2><p>If you use Google or Microsoft to sign in:</p><ul><li>Your authentication is handled by the provider</li><li>MyCompanyDesk never sees or stores your Google/Microsoft password</li><li>You can disconnect social login from <strong>Profile &gt; Connected Apps</strong></li></ul><h2 id="data-protection" tabindex="-1">Data protection <a class="header-anchor" href="#data-protection" aria-label="Permalink to &quot;Data protection&quot;">​</a></h2><p>MyCompanyDesk takes data security seriously:</p><ul><li>All data is transmitted over HTTPS</li><li>Passwords are hashed using bcrypt</li><li>Database connections are encrypted</li><li>Regular backups ensure data safety</li><li>GDPR-compliant data handling</li></ul><h2 id="account-deletion" tabindex="-1">Account deletion <a class="header-anchor" href="#account-deletion" aria-label="Permalink to &quot;Account deletion&quot;">​</a></h2><p>If you need to delete your account:</p><ol><li>Go to <strong>Profile &gt; Data</strong></li><li>Click <strong>Delete Account</strong></li><li>Enter your password to confirm</li><li>All your data is permanently removed</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Account deletion is irreversible. Export your data first if you need a backup.</p></div>',26)])])}const g=e(r,[["render",n]]);export{p as __pageData,g as default};
